    if (stack.has(node)) return true;
    if (visited.has(node)) return false;
    stack.add(node);
    for (const neighbor of graph[node]) if (hasCycle(neighbor)) return true;
    stack.delete(node);
    visited.add(node);
    return false;
  };
  return Object.keys(graph).some(hasCycle);
}

